+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fraction'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: {type: 'fixed' | 'fraction'; value: number}};
+
+type Placement = {start: number; end: number};
+
+const trackExpression = /minmax\\(\\s*[^,]+\\s*,\\s*[^)]+\\s*\\)|\\S+/g;
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (value.endsWith('fr')) {
+		return {type: 'fraction', value: Number.parseFloat(value) || 1};
+	}
+
+	const minmax = /^minmax\\(\\s*(-?(?:\\d+\\.?\\d*|\\.\\d+))\\s*,\\s*(-?(?:\\d+\\.?\\d*|\\.\\d+)(?:fr)?)\\s*\\)$/.exec(value);
+	if (minmax) {
+		const max = minmax[2];
+		return {
+			type: 'minmax',
+			min: Number.parseFloat(minmax[1]),
+			max: max.endsWith('fr')
+				? {type: 'fraction', value: Number.parseFloat(max) || 1}
+				: {type: 'fixed', value: Number.parseFloat(max)},
+		};
+	}
+
+	return {type: 'fixed', value: Number.parseFloat(value) || 0};
+};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template?.trim()) {
+		return [];
+	}
+
+	return (template.match(trackExpression) ?? []).map(parseTrack);
+};
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number' && Number.isInteger(value) && value > 0) {
+		return {start: value - 1, end: value};
+	}
+
+	if (typeof value !== 'string') {
+		return undefined;
+	}
+
+	const match = /^\\s*(\\d+)\\s*\\/\\s*(\\d+)\\s*$/.exec(value);
+	if (!match) {
+		const index = Number.parseInt(value, 10);
+		return Number.isInteger(index) && index > 0
+			? {start: index - 1, end: index}
+			: undefined;
+	}
+
+	const start = Number.parseInt(match[1], 10) - 1;
+	const end = Number.parseInt(match[2], 10) - 1;
+	return start >= 0 && end > start ? {start, end} : undefined;
+};
+
+const childSize = (node: YogaNode, axis: 'width' | 'height'): number =>
+	axis === 'width' ? node.getComputedWidth() : node.getComputedHeight();
+
+const sizeTracks = (
+	tracks: Track[],
+	available: number,
+	gap: number,
+	items: Array<{node: YogaNode; placement: Placement}>,
+	axis: 'width' | 'height',
+): number[] => {
+	const sizes = tracks.map(track =>
+		track.type === 'fixed'
+			? track.value
+			: track.type === 'minmax'
+				? track.min
+				: 0,
+	);
+
+	for (let index = 0; index < tracks.length; index++) {
+		const track = tracks[index];
+		if (track.type !== 'auto' && !(track.type === 'minmax' && track.max.type === 'fixed')) {
+			continue;
+		}
+
+		const contentSize = Math.max(
+			0,
+			...items
+				.filter(item => item.placement.start === index && item.placement.end === index + 1)
+				.map(item => childSize(item.node, axis)),
+		);
+		sizes[index] = track.type === 'auto'
+			? contentSize
+			: Math.min(track.max.value, Math.max(track.min, contentSize));
+	}
+
+	const fractional = tracks.flatMap((track, index) => {
+		if (track.type === 'fraction') {
+			return [{index, value: track.value}];
+		}
+
+		if (track.type === 'minmax' && track.max.type === 'fraction') {
+			return [{index, value: track.max.value}];
+		}
+
+		return [];
+	});
+	const remaining = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - sizes.reduce((total, size) => total + size, 0));
+	const totalFraction = fractional.reduce((total, track) => total + track.value, 0);
+	for (const track of fractional) {
+		sizes[track.index] += totalFraction > 0 ? remaining * (track.value / totalFraction) : 0;
+	}
+
+	return sizes;
+};
+
+const getGap = (node: YogaNode, gutter: number): number => node.getGap(gutter);
+
+const layoutGrid = (element: DOMElement): void => {
+	if (element.style.display !== 'grid' || !element.yogaNode) {
+		return;
+	}
+
+	const children = element.childNodes.filter(
+		(child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode),
+	);
+	let columns = parseTracks(element.style.gridTemplateColumns);
+	if (columns.length === 0) {
+		columns = [{type: 'auto'}];
+	}
+	let rows = parseTracks(element.style.gridTemplateRows);
+	const placements: Array<{node: DOMElement; column: Placement; row: Placement}> = [];
+	const occupied = new Set<string>();
+	let cursor = 0;
+
+	for (const child of children) {
+		const explicitColumn = parsePlacement(child.style.gridColumn);
+		const explicitRow = parsePlacement(child.style.gridRow);
+		let column = explicitColumn;
+		let row = explicitRow;
+		if (!column || !row) {
+			while (occupied.has(`${Math.floor(cursor / columns.length)}:${cursor % columns.length}`)) {
+				cursor++;
+			}
+			const automaticRow = Math.floor(cursor / columns.length);
+			const automaticColumn = cursor % columns.length;
+			column ??= {start: automaticColumn, end: automaticColumn + 1};
+			row ??= {start: automaticRow, end: automaticRow + 1};
+			cursor++;
+		}
+
+		for (let y = row.start; y < row.end; y++) {
+			for (let x = column.start; x < column.end; x++) {
+				occupied.add(`${y}:${x}`);
+			}
+		}
+		placements.push({node: child, column, row});
+	}
+
+	const requiredRows = Math.max(0, ...placements.map(item => item.row.end));
+	while (rows.length < requiredRows) {
+		rows.push({type: 'auto'});
+	}
+	if (rows.length === 0) {
+		rows.push({type: 'auto'});
+	}
+
+	const yoga = element.yogaNode;
+	const horizontalPadding = yoga.getComputedPadding(Yoga.EDGE_LEFT) + yoga.getComputedPadding(Yoga.EDGE_RIGHT) + yoga.getComputedBorder(Yoga.EDGE_LEFT) + yoga.getComputedBorder(Yoga.EDGE_RIGHT);
+	const verticalPadding = yoga.getComputedPadding(Yoga.EDGE_TOP) + yoga.getComputedPadding(Yoga.EDGE_BOTTOM) + yoga.getComputedBorder(Yoga.EDGE_TOP) + yoga.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const columnGap = getGap(yoga, Yoga.GUTTER_COLUMN);
+	const rowGap = getGap(yoga, Yoga.GUTTER_ROW);
+	const columnSizes = sizeTracks(columns, Math.max(0, yoga.getComputedWidth() - horizontalPadding), columnGap, placements.map(item => ({node: item.node.yogaNode!, placement: item.column})), 'width');
+	const rowSizes = sizeTracks(rows, Math.max(0, yoga.getComputedHeight() - verticalPadding), rowGap, placements.map(item => ({node: item.node.yogaNode!, placement: item.row})), 'height');
+	const totalHeight = rowSizes.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rowSizes.length - 1) + verticalPadding;
+	if (element.style.height === undefined) {
+		yoga.setHeight(totalHeight);
+	}
+
+	for (const item of placements) {
+		const child = item.node.yogaNode!;
+		const left = columnSizes.slice(0, item.column.start).reduce((total, size) => total + size, 0) + columnGap * item.column.start;
+		const top = rowSizes.slice(0, item.row.start).reduce((total, size) => total + size, 0) + rowGap * item.row.start;
+		const width = columnSizes.slice(item.column.start, item.column.end).reduce((total, size) => total + size, 0) + columnGap * Math.max(0, item.column.end - item.column.start - 1);
+		const height = rowSizes.slice(item.row.start, item.row.end).reduce((total, size) => total + size, 0) + rowGap * Math.max(0, item.row.end - item.row.start - 1);
+		child.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.setPosition(Yoga.EDGE_LEFT, left);
+		child.setPosition(Yoga.EDGE_TOP, top);
+		child.setWidth(width);
+		child.setHeight(height);
+	}
+};
+
+export const layoutGrids = (element: DOMElement): void => {
+	for (const child of element.childNodes) {
+		if (child.nodeName !== '#text') {
+			layoutGrids(child);
+		}
+	}
+
+	layoutGrid(element);
+};
