export const layoutGrids = (element: DOMElement): void => {
	for (const child of element.childNodes) {
		if (child.nodeName !== '#text') {
			layoutGrids(child);
		}
	}

	layoutGrid(element);

	if (element.nodeName === 'ink-root' && element.yogaNode) {
		const requiredHeight = element.childNodes.reduce((height, child) => {
			if (!child.yogaNode) {
				return height;
			}

			const top = child.yogaNode.getComputedTop();
			const childHeight =
				child.internal_gridHeight ?? child.yogaNode.getComputedHeight();
			return Math.max(
				height,
				(Number.isFinite(top) ? top : 0) +
					(Number.isFinite(childHeight) ? childHeight : 0),
			);
		}, 0);
		element.internal_gridHeight = requiredHeight;
		element.yogaNode.setHeight(requiredHeight);
	}
};

export const prepareGridLayout = (element: DOMElement): void => {
	if (element.nodeName === 'ink-root') {
		element.internal_gridHeight = undefined;
	}
	if (element.style.display === 'grid' && element.style.height === undefined) {
		element.yogaNode?.setHeightAuto();
		element.internal_gridHeight = undefined;
	}

	if (element.style.display !== 'grid') {
		element.internal_gridPosition = undefined;
	}

